const allLocations: RegionNearby[] = [...umlandLocations, ...moedlingLocations];

export { umlandLocations, moedlingLocations, allLocations };

/**
 * Nachbarorte für die interne Verlinkung: erst die Prioritäten (dürfen Cluster-übergreifend
 * sein), dann der Rest des eigenen Clusters — gedeckelt auf 11 Einträge, damit das Grid
 * auf der Seite übersichtlich bleibt.
 */
function getNearby(currentSlug: string, priority: string[]): RegionNearby[] {
  const cluster = moedlingLocations.some(l => l.slug === currentSlug) ? moedlingLocations : umlandLocations;
  const ordered = priority
    .map(slug => allLocations.find(l => l.slug === slug))
    .filter((l): l is RegionNearby => l !== undefined && l.slug !== currentSlug);
  const rest = cluster.filter(l => l.slug !== currentSlug && !priority.includes(l.slug));
  return [...ordered, ...rest].slice(0, 11);
}

